"use strict";(self.webpackChunkblogv2_dev=self.webpackChunkblogv2_dev||[]).push([[4215],{7503:(n,s,a)=>{a.r(s),a.d(s,{data:()=>e});const e={key:"v-dd5bc3f8",path:"/algorithm/data_struct/linkedlist.html",title:"Linked List",lang:"zh-CN",frontmatter:{title:"Linked List",Date:"2022-2-7",summary:"Linked List Reverse Linked List Iterative method; Recursive method; 1) Divide the list in two parts - first node and rest of the linked list. 2) Call reverse for the rest of the li",head:[["meta",{property:"og:url",content:"https://vueblog.weigao.cc/algorithm/data_struct/linkedlist.html"}],["meta",{property:"og:site_name",content:"WW"}],["meta",{property:"og:title",content:"Linked List"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-04-17T08:12:32.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:modified_time",content:"2022-04-17T08:12:32.000Z"}]]},excerpt:"",headers:[{level:2,title:"Linked List",slug:"linked-list",children:[{level:3,title:"Reverse Linked List",slug:"reverse-linked-list",children:[]},{level:3,title:"Intersection of Linked List",slug:"intersection-of-linked-list",children:[]}]},{level:2,title:"Implement LRU",slug:"implement-lru",children:[]}],git:{createdTime:1648036546e3,updatedTime:1650183152e3,contributors:[{name:"chenweigao",email:"297859260@qq.com",commits:1},{name:"chenweigao",email:"chenweigao1@huawei.com",commits:1}]},readingTime:{minutes:2.58,words:773},filePathRelative:"algorithm/data_struct/linkedlist.md"}},2503:(n,s,a)=>{a.r(s),a.d(s,{default:()=>y});var e=a(6252);const t=(0,e.uE)('<h2 id="linked-list" tabindex="-1"><a class="header-anchor" href="#linked-list" aria-hidden="true">#</a> Linked List</h2><h3 id="reverse-linked-list" tabindex="-1"><a class="header-anchor" href="#reverse-linked-list" aria-hidden="true">#</a> Reverse Linked List</h3><ul><li>Iterative method</li></ul><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">reverseList</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> head<span class="token punctuation">)</span><span class="token punctuation">:</span>\n\n    preNode <span class="token operator">=</span> <span class="token boolean">None</span>\n    curNode <span class="token operator">=</span> head\n\n    <span class="token keyword">while</span> curNode <span class="token keyword">is</span> <span class="token keyword">not</span> <span class="token boolean">None</span><span class="token punctuation">:</span>\n        <span class="token builtin">next</span> <span class="token operator">=</span> curNode<span class="token punctuation">.</span><span class="token builtin">next</span>\n        curNode<span class="token punctuation">.</span><span class="token builtin">next</span> <span class="token operator">=</span> preNode\n        preNode <span class="token operator">=</span> curNode\n        curNode <span class="token operator">=</span> <span class="token builtin">next</span>\n\n    <span class="token keyword">return</span> preNode\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>Recursive method</li></ul><ol><li>Divide the list in two parts - first node and rest of the linked list.</li><li>Call reverse for the rest of the linked list.</li><li>Link rest to first.</li><li>Fix head pointer</li></ol><p>由于迭代较快，故建议经常使用迭代法。</p><h3 id="intersection-of-linked-list" tabindex="-1"><a class="header-anchor" href="#intersection-of-linked-list" aria-hidden="true">#</a> Intersection of Linked List</h3><p>判断两个链表是否有交叉(Intersection), LC160.</p><p>实现思路有：</p><ul><li>根据链表是否有环判断</li></ul><p>先遍历一个链表找到其尾部，然后将尾部的 next 指针指向另一个链表，这样子两个链表就合成了一个链表，判断原来的两个链表是否有交叉也就变成了判断一个<strong>单链表是否有环</strong>。</p><p>找出交点的方法是，遍历两个链表，长度较长的链表指针向后移动 |len1 - len2| 个单位，然后开始遍历两个链表，判断节点是否相等（节点的地址）。</p><ul><li>根据总结的规律判断</li></ul><p>该方法比较巧妙，代码如下：</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">getIntersectionNode</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> headA<span class="token punctuation">,</span> headB<span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">if</span> headA <span class="token keyword">is</span> <span class="token boolean">None</span> <span class="token keyword">or</span> headB <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span>\n        <span class="token keyword">return</span> <span class="token boolean">None</span>\n\n    pa <span class="token operator">=</span> headA\n    pb <span class="token operator">=</span> headB\n\n    <span class="token keyword">while</span> pa <span class="token keyword">is</span> <span class="token keyword">not</span> pb<span class="token punctuation">:</span>\n        pa <span class="token operator">=</span> headB <span class="token keyword">if</span> pa <span class="token keyword">is</span> <span class="token boolean">None</span> <span class="token keyword">else</span> pa<span class="token punctuation">.</span><span class="token builtin">next</span>\n        pb <span class="token operator">=</span> headA <span class="token keyword">if</span> pb <span class="token keyword">is</span> <span class="token boolean">None</span> <span class="token keyword">else</span> pb<span class="token punctuation">.</span><span class="token builtin">next</span>\n\n    <span class="token keyword">return</span> pa\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>核心思路在于，同时遍历两个链表，如果到链表结束，则将指针指向另一个链表，遍历直到两个移动的指针相等。</p><div class="custom-container tip"><p class="custom-container-title">判断单链表是否有环</p><p>一般判断单链表是否有环的方法是设置一块一慢两个指针，看其是否会相等。</p></div><h2 id="implement-lru" tabindex="-1"><a class="header-anchor" href="#implement-lru" aria-hidden="true">#</a> Implement LRU</h2><p>LRU 为最近最少使用算法，常常用于缓存技术中，其实现方式为<strong>循环双向链表</strong>，实现思想为：</p><p>将 chche 的所有位置都用双向链表链接起来，当一个位置被命中以后，将该位置指向链表头的位置，新加入的 chche 直接加到链表头中。</p><p>这样，在多次进行 cache 操作后，最近被命中的，就会被向链表头方向移动，而没被命中的向链表后面移动。</p><p>缓存已满的时候新加入的数据节点插入链表头部，而删除链表的尾节点。</p>',23),p=(0,e.Uk)("具体的实现代码可以"),o={href:"https://github.com/chenweigao/_code/blob/30551f4e92dab06e127be316cd2f3950eda099ef/LeetCode/LC146_LRU_cache_double_linked_list.py",target:"_blank",rel:"noopener noreferrer"},i=(0,e.Uk)("参考 GitHub"),l=(0,e.uE)('<div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">LRUCache</span><span class="token punctuation">:</span>\n    <span class="token keyword">def</span> <span class="token function">__init__</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> capacity<span class="token punctuation">:</span> <span class="token builtin">int</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n        self<span class="token punctuation">.</span>capacity <span class="token operator">=</span> capacity\n        seld<span class="token punctuation">.</span>dic <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>\n        self<span class="token punctuation">.</span>head <span class="token operator">=</span> Node<span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span>\n        self<span class="token punctuation">.</span>tail <span class="token operator">=</span> Node<span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">)</span>\n        self<span class="token punctuation">.</span>head<span class="token punctuation">.</span><span class="token builtin">next</span> <span class="token operator">=</span> self<span class="token punctuation">.</span>tail\n        self<span class="token punctuation">.</span>tail<span class="token punctuation">.</span>prev <span class="token operator">=</span> self<span class="token punctuation">.</span>head\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>思路是初始化一个 <code>dict</code> 用于存储，对双向链表进行操作的同时对这个 <code>dict</code> 进行赋值操作，<code>dict</code> 的结构为：</p><ul><li><p>key: LRUCache 中的 key</p></li><li><p>value: 一个 <code>Node</code> 类型的节点，存储其 <code>prev</code> 和 <code>next</code> 信息以及最关键的 <code>value</code></p></li></ul><p>其 <code>put()</code> 方法为：</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">put</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> key<span class="token punctuation">:</span> <span class="token builtin">int</span><span class="token punctuation">,</span> value<span class="token punctuation">:</span> <span class="token builtin">int</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token boolean">None</span><span class="token punctuation">:</span>\n    <span class="token keyword">if</span> key <span class="token keyword">in</span> self<span class="token punctuation">.</span>dic<span class="token punctuation">:</span>\n        self<span class="token punctuation">.</span>_remove<span class="token punctuation">(</span>dic<span class="token punctuation">[</span>key<span class="token punctuation">]</span><span class="token punctuation">)</span>\n    n <span class="token operator">=</span> Node<span class="token punctuation">(</span>key<span class="token punctuation">,</span> value<span class="token punctuation">)</span>\n    self<span class="token punctuation">.</span>_add<span class="token punctuation">(</span>n<span class="token punctuation">)</span>\n    self<span class="token punctuation">.</span>dic<span class="token punctuation">[</span>key<span class="token punctuation">]</span> <span class="token operator">=</span> n\n    <span class="token keyword">if</span> <span class="token builtin">len</span><span class="token punctuation">(</span>self<span class="token punctuation">.</span>dic<span class="token punctuation">)</span> <span class="token operator">&gt;</span> self<span class="token punctuation">.</span>capacity<span class="token punctuation">:</span>\n        first_node <span class="token operator">=</span> self<span class="token punctuation">.</span>head<span class="token punctuation">.</span><span class="token builtin">next</span>\n        self<span class="token punctuation">.</span>_remove<span class="token punctuation">(</span>first_node<span class="token punctuation">)</span>\n        <span class="token keyword">del</span> self<span class="token punctuation">.</span>dic<span class="token punctuation">[</span>first_node<span class="token punctuation">.</span>key<span class="token punctuation">]</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>然后使用双向链表的操作进行插入（尾插）和删除（第一个节点）</p>',6),c=(0,e.Uk)("也可以使用 Python 中的 "),d=(0,e._)("code",null,"collection.OrderedDict",-1),u=(0,e.Uk)(" 来进行存储，使用其 "),r=(0,e._)("code",null,"move_to_end()",-1),k=(0,e.Uk)(" 和 "),v=(0,e._)("code",null,"popitem()",-1),m=(0,e.Uk)(" 方法，具体代码可以"),h={href:"https://github.com/chenweigao/_code/blob/30551f4e92dab06e127be316cd2f3950eda099ef/LeetCode/LC146_LRU_ordereddic.py",target:"_blank",rel:"noopener noreferrer"},b=(0,e.Uk)("参考这里"),f={},y=(0,a(3744).Z)(f,[["render",function(n,s){const a=(0,e.up)("ExternalLinkIcon");return(0,e.wg)(),(0,e.iD)("div",null,[t,(0,e._)("p",null,[p,(0,e._)("a",o,[i,(0,e.Wm)(a)])]),l,(0,e._)("p",null,[c,d,u,r,k,v,m,(0,e._)("a",h,[b,(0,e.Wm)(a)])])])}]])},3744:(n,s)=>{s.Z=(n,s)=>{const a=n.__vccOpts||n;for(const[n,e]of s)a[n]=e;return a}}}]);